request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?lang WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "38b17e822a5e4307ae051694293e4d0f" .
  ?model tai:belongsTo ?org ;
         a bboExt:Model ;
         bbo:name ?modelName .
  OPTIONAL { ?model bboExt:language ?lang . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?modelName ?definitions ?prop ?value WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "38b17e822a5e4307ae051694293e4d0f" .
  ?model tai:belongsTo ?org ;
         a bboExt:Model ;
         bbo:name ?modelName .
  ?definitions tai:belongsTo ?model .
  ?definitions ?prop ?value .
  FILTER(CONTAINS(LCASE(STR(?prop)), "lang"))
}
LIMIT 25
